steps.script:
var bg = GameState.get_unit("U_BOYZ_E")
var bg_kw = bg.get("meta", {}).get("keywords", [])
var champ = {
	"id": "U_BLADE_CHAMP_TEST",
	"squad_id": "U_BLADE_CHAMP_TEST",
	"owner": bg.get("owner", 1),
	"status": bg.get("status", 0),
	"meta": {"name": "Blade Champion", "keywords": ["CHARACTER"], "leader_data": {"can_lead": bg_kw.duplicate()}, "stats": {"move": 6, "wounds": 6}, "points": 120},
	"models": [{"id": "m1", "alive": true, "base_mm": 40, "position": null, "wounds": 6, "current_wounds": 6}],
	"attached_to": null,
	"attachment_data": {"attached_characters": []},
	"flags": {}
}
GameState.state.units["U_BLADE_CHAMP_TEST"] = champ
CharacterAttachmentManager.attach_character("U_BLADE_CHAMP_TEST", "U_BOYZ_E")
return GameState.get_unit("U_BOYZ_E").get("attachment_data", {}).get("attached_characters", []).size()

var mc = tree.current_scene.get_node_or_null("MovementController")
if mc == null:
	return false
mc._refresh_unit_list()
var ul = mc.unit_list
for i in range(ul.get_item_count()):
	if str(ul.get_item_metadata(i)) == "U_BOYZ_E":
		var t = ul.get_item_text(i)
		return t.contains("Custodian Guard Alpha") and t.contains("Blade Champion")
return false

var mc = tree.current_scene.get_node_or_null("MovementController")
if mc == null:
	return "NO_MOVEMENT_CONTROLLER"
mc._refresh_unit_list()
var ul = mc.unit_list
if ul == null:
	return "NO_UNIT_LIST"
for i in range(ul.get_item_count()):
	if str(ul.get_item_metadata(i)) == "U_BOYZ_E":
		return ul.get_item_text(i).count("Blade Champion")
return -1
